import io.cucumber.java.en.Given;
import io.cucumber.java.en.Then;
import io.cucumber.java.en.When;
import org.apache.commons.math3.geometry.euclidean.threed.SubLine;
import org.apache.commons.math3.geometry.euclidean.threed.Vector3D;

import static org.junit.Assert.assertNull;

import java.util.HashMap;
import java.util.Map;

public class StepDefs {

    private Map<String, SubLine> subLines = new HashMap<>();
    private Object result;

    @Given("a sub-line {string} defined by points ({double}, {double}, {double}) and ({double}, {double}, {double})")
    public void a_sub_line_defined_by_points(String name, double x1, double y1, double z1, double x2, double y2, double z2) {
        try {
            Vector3D p1 = new Vector3D(x1, y1, z1);
            Vector3D p2 = new Vector3D(x2, y2, z2);
            SubLine subLine = new SubLine(p1, p2);
            subLines.put(name, subLine);
        } catch (Exception e) {
            // Capture exception if needed for testing purposes
            result = e;
        }
    }

    @When("I compute the intersection of {string} and {string}")
    public void i_compute_the_intersection_of(String subLine1Name, String subLine2Name) {
        try {
            SubLine subLine1 = subLines.get(subLine1Name);
            SubLine subLine2 = subLines.get(subLine2Name);

            if (subLine1 != null && subLine2 != null) {
                // Using true parameter as per the original test
                result = subLine1.intersection(subLine2, true);
            } else {
                result = null;
            }
        } catch (Exception e) {
            result = e;
        }
    }

    @Then("the result should be null")
    public void the_result_should_be_null() {
        assertNull("Expected result to be null, but was: " + result, result);
    }
}

